INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (3, 1, 'BBSカットオフ（退院時歩行自立）', 'cutoff', `field` = 'bbs_score', `fieldLabel` = 'Berg Balance Scale (BBS)', `negativeMessage` = '退院時：歩行介助が必要な可能性（BBS < 14）', `operator` = '>=', `positiveMessage` = '退院時：歩行自立の可能性が高い（BBS ≥ 14）', `threshold` = 14, `type` = 'cutoff', `unit` = '点', , 73, 89, NULL, 0.81, NULL, 'https://pmc.ncbi.nlm.nih.gov/articles/PMC8370698/', NULL, '2026-05-06 07:42:10', '2026-05-06 07:42:10');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (5, 1, 'Perry歩行速度分類', 'scoring_system', `items` = '[object Object]', `maxScore` = 3, `negativeMessage` = 'Household（屋内中心の歩行レベル）', `positiveMessage` = 'Limited Community以上（地域歩行が可能なレベル）', `threshold` = 2, `type` = 'scoring_system', , NULL, NULL, NULL, NULL, NULL, 'https://pubmed.ncbi.nlm.nih.gov/7762050/', NULL, '2026-05-06 07:42:10', '2026-05-06 07:42:10');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30001, 1, '麻痺側膝伸展筋力カットオフ（病棟歩行自立）', 'cutoff', `field` = 'knee_ext_paretic_nm_kg', `fieldLabel` = '麻痺側膝伸展筋力（Nm/kg）', `negativeMessage` = '病棟歩行自立は困難な可能性（麻痺側膝伸展筋力 < 0.631 Nm/kg）', `notes` = '対象: 回復期脳卒中片麻痺患者658名（中央値74歳）。Youden index法によるROC曲線から算出。kgf/kg換算では ≥ 0.178 kgf/kg。', `operator` = '>=', `positiveMessage` = '病棟歩行自立の可能性が高い（麻痺側膝伸展筋力 ≥ 0.631 Nm/kg）', `threshold` = 0.631, `type` = 'cutoff', `unit` = 'Nm/kg', , NULL, NULL, NULL, 0.713, NULL, 'https://www.jstage.jst.go.jp/article/rigaku/49/4/49_12232/_article/-char/ja', NULL, '2026-05-07 01:04:30', '2026-05-07 01:04:30');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30002, 1, '両側合計膝伸展筋力カットオフ（病棟歩行自立）', 'cutoff', `field` = 'knee_ext_total_nm_kg', `fieldLabel` = '両側合計膝伸展筋力（Nm/kg）', `negativeMessage` = '病棟歩行自立は困難な可能性（両側合計膝伸展筋力 < 1.621 Nm/kg）', `notes` = 'AUCは3指標中最高（0.729）。kgf/kg換算では ≥ 0.455 kgf/kg。', `operator` = '>=', `positiveMessage` = '病棟歩行自立の可能性が高い（両側合計膝伸展筋力 ≥ 1.621 Nm/kg）', `threshold` = 1.621, `type` = 'cutoff', `unit` = 'Nm/kg', , NULL, NULL, NULL, 0.726, NULL, 'https://www.jstage.jst.go.jp/article/rigaku/49/4/49_12232/_article/-char/ja', NULL, '2026-05-07 01:04:31', '2026-05-07 01:04:31');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30003, 1, 'FBS・起居動作・認知機能による決定木（入院3ヶ月後歩行自立）', 'decision_tree', `description` = '信号検出分析法（Signal Detection Analysis）による決定木。入院時情報から3ヶ月後の歩行自立を予測する。', `nodes` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', `notes` = '対象: 初発脳卒中患者251名（年齢68.4±11.1歳）。全体歩行自立率25.9%（65/251名）。グループ4を参照群とした場合のOR: グループ3=4.9, グループ2=7.6, グループ1=37.3。', `type` = 'decision_tree', , 63.1, 89.8, NULL, NULL, NULL, 'https://www.jstage.jst.go.jp/article/rika/33/1/33_145/_article/-char/ja/', NULL, '2026-05-07 01:04:31', '2026-05-07 01:04:31');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30004, 1, '歩行自立スコア（年齢・BBS・FIM運動・FIM認知）', 'scoring_system', `description` = '入棟時情報から退院時の平地歩行自立を予測するスコアリングシステム。各因子のROC曲線から最適カットオフ値を算出し、各1点を割り振る（合計0-4点）。', `items` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', `maxScore` = 4, `negativeMessage` = '退院時平地歩行自立は困難な可能性（スコア≤2点: 自立率0-40.6%）', `notes` = '対象: 229名（自立群117名, 非自立群112名）。最適カットオフ3点: 感度80.3%, 特異度85.7%, AUC=0.890。', `positiveMessage` = '退院時平地歩行自立の可能性が高い（スコア≥3点: 自立率78.9-92.5%）', `scoreProbabilityTable` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', `threshold` = 3, `type` = 'scoring_system', , 80.3, 85.7, NULL, 0.89, NULL, 'https://www.jstage.jst.go.jp/article/rika/40/4/40_181/_article/-char/ja/', NULL, '2026-05-07 01:04:31', '2026-05-07 01:04:31');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30005, 1, '平地歩行自立時期予測ノモグラム（Cox比例ハザードモデル）', 'nomogram', `intercept` = 0, `negativeLabel` = '歩行自立困難', `note` = 'Cox比例ハザード分析に基づくノモグラム。スコアが高いほど歩行自立が早期に達成される確率が高い。C-index=0.858（ブートストラップ0.851）。MAE=0.022', `positiveLabel` = '歩行自立（発症30〜120日以内）', `threshold` = 0, `type` = 'nomogram', `variables` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', , NULL, NULL, NULL, 0.858, NULL, 'https://www.jstage.jst.go.jp/article/jjrmc/62/11/62_25020/_article/-char/ja', NULL, '2026-05-07 01:04:32', '2026-05-07 01:04:32');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30006, 1, '変化量を用いた決定木・重度群（ΔBBS・ΔFIM運動）', 'decision_tree', `nodes` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', `type` = 'decision_tree', '[object Object]', 63.4, 83.9, NULL, 0.76, NULL, 'http://aichi-npopt.jp/dl/info_paper_back/35_2_15.pdf', NULL, '2026-05-07 01:04:32', '2026-05-07 01:04:32');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30007, 1, '変化量を用いた決定木・中等度群（ΔFIM運動・CBA）', 'decision_tree', `nodes` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', `type` = 'decision_tree', '[object Object]', '[object Object]', 81.4, 59.5, NULL, 0.79, NULL, 'http://aichi-npopt.jp/dl/info_paper_back/35_2_15.pdf', NULL, '2026-05-07 01:04:33', '2026-05-07 01:04:33');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (30008, 30001, '退院時FIM運動項目予測 重回帰式', 'regression', `coefficients` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', `description` = '重回帰分析による退院時FIM運動項目合計スコアの予測式。入院時FIM運動・認知項目、年齢、発症から入院までの日数を用いる。', `formula` = 'fim_motor_discharge = fim_motor_admission * 0.97 + fim_cognitive_admission * 0.56 - age * 0.26 - days_onset_to_admission * 0.16 + 47.2', `intercept` = 47.2, `negativeMessage` = '退院時FIM運動項目の予測値が低い（要介助の可能性）', `notes` = '対象: 498名（2021年4月〜2023年3月）。5-fold交差検証: R²=0.699, RMSE=13.94。AIモデルとの比較でR²差0.016と小さく、臨床現場での実用性が高い。', `outputField` = 'fim_motor_discharge', `outputFieldLabel` = '退院時FIM運動項目合計（予測値）', `outputRange` = 13, 91, `outputUnit` = '点', `positiveMessage` = '退院時FIM運動項目の予測値が高い（自立度が高い）', `type` = 'regression', , NULL, NULL, NULL, NULL, NULL, 'https://www.jstage.jst.go.jp/article/rigaku/53/2/53_25-12662/_article/-char/ja', NULL, '2026-05-07 01:04:33', '2026-05-07 01:04:33');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60001, 60001, 'BBS入院時スコアによる地域歩行予測（≥29点）', 'cutoff', `field` = 'bbs_score', `fieldLabel` = 'Berg Balance Scale（BBS）入院時スコア', `negativeMessage` = '退院時に地域歩行速度の達成は困難な可能性（BBS<29点）', `notes` = '対象: 入院リハビリ開始時（発症中央値19日）の脳卒中患者123名（カナダ）。4週間の入院リハビリ後の歩行能力を予測。多変量モデルでは脳卒中タイプ（脳出血 OR=0.19）と発症日数（OR=0.93）も有意な予測因子。', `operator` = '>=', `positiveMessage` = '退院時に地域歩行速度（≥0.8 m/s）を達成できる可能性が高い（BBS≥29点）', `threshold` = 29, `type` = 'cutoff', `unit` = '点', '[object Object]', 86, 84, NULL, 0.88, NULL, 'https://doi.org/10.2340/16501977-2280', NULL, '2026-05-07 02:04:26', '2026-05-07 02:04:26');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60002, 1, 'BBS入院時スコアによる非補助歩行予測（非歩行者サブグループ, ≥12点）', 'cutoff', `field` = 'bbs_score', `fieldLabel` = 'Berg Balance Scale（BBS）入院時スコア', `negativeMessage` = '4週間後も補助なし歩行の達成は困難な可能性（BBS<12点）', `notes` = '対象: 入院時に非歩行者（5MWTを補助なしで完遂できない）のサブグループ n=84。BBS単独が有意な予測因子（OR=1.11, 95%CI: 1.05-1.17）。AUC=0.73（95%CI: 0.62-0.84）。', `operator` = '>=', `positiveMessage` = '4週間の入院リハビリ後に補助なし歩行を達成できる可能性がある（BBS≥12点）', `threshold` = 12, `type` = 'cutoff', `unit` = '点', '[object Object]', 74, 68, NULL, 0.73, NULL, 'https://doi.org/10.2340/16501977-2280', NULL, '2026-05-07 02:04:26', '2026-05-07 02:04:26');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60003, 60001, 'TUGによる地域歩行予測（<14.77秒）', 'cutoff', `field` = 'tug_seconds', `fieldLabel` = 'Timed Up and Go（TUG）テスト', `negativeMessage` = '地域歩行速度の達成は困難な可能性（TUG≥14.77秒）', `notes` = '対象: 脳卒中片麻痺患者75名（韓国）。地域歩行群（n=40）vs 限定的地域歩行群（n=35）の比較。ロジスティック回帰でOR=0.038（最も強い予測因子）。', `operator` = '<', `positiveMessage` = '地域歩行速度（>0.8 m/s）を達成できる可能性が高い（TUG<14.77秒）', `threshold` = 14.77, `type` = 'cutoff', `unit` = '秒', , 93, 74, NULL, 0.88, NULL, 'https://pubmed.ncbi.nlm.nih.gov/27630394/', NULL, '2026-05-07 02:04:47', '2026-05-07 02:04:47');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60004, 60001, 'BBSによる地域歩行予測（>46.5点）', 'cutoff', `field` = 'bbs_score', `fieldLabel` = 'Berg Balance Scale（BBS）', `negativeMessage` = '地域歩行速度の達成は困難な可能性（BBS≤46.5点）', `notes` = 'AUC=0.80（中程度の精度）。ロジスティック回帰でOR=0.084。FMA>25.5点と組み合わせると精度向上の可能性。', `operator` = '>', `positiveMessage` = '地域歩行速度（>0.8 m/s）を達成できる可能性が高い（BBS>46.5点）', `threshold` = 46.5, `type` = 'cutoff', `unit` = '点', , 70, 82, NULL, 0.8, NULL, 'https://pubmed.ncbi.nlm.nih.gov/27630394/', NULL, '2026-05-07 02:04:48', '2026-05-07 02:04:48');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60005, 60001, 'FMA下肢スコアによる地域歩行予測（>25.5点）', 'cutoff', `field` = 'fma_lower', `fieldLabel` = 'Fugl-Meyer Assessment 下肢スコア（FMA-LE）', `negativeMessage` = '地域歩行速度の達成は困難な可能性（FMA-LE≤25.5点）', `notes` = 'AUC=0.80。PPV=80%（陽性的中率が高い）。ロジスティック回帰でOR=0.053。', `operator` = '>', `positiveMessage` = '地域歩行速度（>0.8 m/s）を達成できる可能性が高い（FMA-LE>25.5点）', `threshold` = 25.5, `type` = 'cutoff', `unit` = '点（最大34点）', , NULL, NULL, NULL, 0.8, NULL, 'https://doi.org/10.1589/jpts.28.2184', NULL, '2026-05-07 02:04:48', '2026-05-07 02:04:48');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60006, 1, '脳卒中分類・FIM運動・FIM認知・要介護区分による決定木（退棟時歩行自立）', 'decision_tree', `description` = 'CART（Classification and Regression Tree）分析による決定木。入棟時情報から退棟時の歩行自立（FIM歩行項目6点以上）を予測する。', `nodes` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', `notes` = '対象: 回復期リハビリテーション病棟入棟患者（n=127）。正診率89.5%（95%CI: 82.0-94.7）、感度83.3%、特異度97.8%、AUC=0.918（95%CI: 0.862-0.974）。', `type` = 'decision_tree', , 83.3, 97.8, 0.895, 0.918, NULL, 'https://www.jstage.jst.go.jp/article/opta/3/1/3_16/_article/-char/ja', NULL, '2026-05-07 02:04:49', '2026-05-07 02:04:49');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60007, 1, '重度片麻痺患者の良好な機能回復予測（年齢・病型・皮質病変）', 'composite_rule', `negativeMessage` = '機能回復は限定的な可能性（重度片麻痺患者の24%のみFIM≥100達成）', `positiveMessage` = '良好な機能回復（FIM≥100または在宅復帰）の可能性がある（年齢<70歳 & 脳出血 & 皮質病変なし）', `root` = '[object Object]', `type` = 'composite_rule', '[object Object]', NULL, NULL, NULL, NULL, NULL, 'https://pubmed.ncbi.nlm.nih.gov/35975271/', NULL, '2026-05-07 02:04:49', '2026-05-07 02:04:49');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60008, 1, '半側空間無視と認知障害の複合が歩行自立回復に与える影響', 'composite_rule', `negativeMessage` = 'USN+認知障害の合併 → 歩行自立困難リスク高（自立率10%、OR=5.55）', `positiveMessage` = 'USN+認知障害の合併なし → 歩行自立の可能性あり（USN単独では有意な関連なし）', `root` = '[object Object]', `type` = 'composite_rule', , NULL, NULL, NULL, NULL, NULL, 'https://medicaljournalssweden.se/jrm/article/view/9437', NULL, '2026-05-07 02:04:50', '2026-05-07 02:04:50');
INSERT INTO literature_rules (id, outcomeId, name, ruleType, ruleDefinition, applyConditions, sensitivity, specificity, accuracy, auc, sourceTitle, sourceUrl, notes, createdAt, updatedAt) VALUES (60009, 1, '非歩行者の歩行自立予測因子（メタ解析: 座位保持・ADL・下肢筋力等）', 'scoring_system', `description` = '発症早期の非歩行者における3・6ヶ月後の歩行自立予測因子のメタ解析。各因子の存在（1点）/欠如（0点）でスコアリングし、リスク評価を行う。', `items` = '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', '[object Object]', `maxScore` = 7, `negativeMessage` = '歩行自立の予後不良因子が多い（スコア<5点）', `notes` = '発症早期の非歩行者を対象とした系統的レビュー＆メタ解析（n=18研究）。座位保持とADL自立が最も強い予測因子。皮質脊髄路の保存（OR=8.3）も重要だが画像評価が必要。', `positiveMessage` = '歩行自立の予後良好因子が多い（スコア≥5点）', `threshold` = 5, `type` = 'scoring_system', '[object Object]', NULL, NULL, NULL, NULL, NULL, 'https://pubmed.ncbi.nlm.nih.gov/34238016/', NULL, '2026-05-07 02:04:50', '2026-05-07 02:04:50');
